package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases – проверяет граничные (edge)‑случаи
// метода Order.CalculateTotal().  В проекте уже есть тесты
// TestUnitOrderCalculateTotal*, поэтому здесь мы покрываем сценарии,
// которые в них не рассматриваются:
//
//   1. nil‑срез Items (должен вести себя так же, как пустой срез);
//   2. элементы с нулевым Quantity / Price – их вклад в сумму равен 0;
//   3. смешанный набор (ноль + положительные значения);
//   4. очень большие числа, которые могут привести к переполнению float64
//      (ожидаем +Inf, а не паники);
//   5. отрицательные Quantity/Price – такие данные попадают в расчёт,
//      но в реальном коде они отсекаются валидацией. Тест проверяет, что
//      метод «честно» суммирует их (получаем отрицательный итог).
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	tests := []struct {
		name     string
		items    []OrderItem
		expected float64
	}{
		{
			name:     "nil slice behaves like empty slice",
			items:    nil,
			expected: 0,
		},
		{
			name: "all items have zero quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, UnitPrice: 100.0},
				{ProductID: 2, Quantity: 0, UnitPrice: 250.5},
			},
			expected: 0,
		},
		{
			name: "all items have zero price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, UnitPrice: 0},
				{ProductID: 2, Quantity: 5, UnitPrice: 0},
			},
			expected: 0,
		},
		{
			name: "mixed zero and positive values",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, UnitPrice: 49.99}, // 99.98
				{ProductID: 2, Quantity: 0, UnitPrice: 123.45}, // 0
				{ProductID: 3, Quantity: 5, UnitPrice: 0},      // 0
				{ProductID: 4, Quantity: 1, UnitPrice: 10.00}, // 10.00
			},
			expected: 109.98,
		},
		{
			name: "very large numbers – expect +Inf, not panic",
			items: []OrderItem{
				{ProductID: 1, Quantity: math.MaxInt64, UnitPrice: math.MaxFloat64},
				{ProductID: 2, Quantity: math.MaxInt64, UnitPrice: math.MaxFloat64},
			},
			// При умножении двух максимальных значений получаем +Inf.
			expected: math.Inf(1),
		},
		{
			name: "negative quantity and price – method sums literally",
			items: []OrderItem{
				{ProductID: 1, Quantity: -2, UnitPrice: 50.0}, // -100
				{ProductID: 2, Quantity: 3, UnitPrice: -20.0}, // -60
				{ProductID: 3, Quantity: -1, UnitPrice: -10.0}, // +10
			},
			expected: -150,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			// Arrange
			order := Order{
				Items: tt.items,
			}

			// Act
			total := order.CalculateTotal()

			// Assert
			if math.IsInf(tt.expected, 1) {
				if !math.IsInf(total, 1) {
					t.Fatalf("expected total to be +Inf, got %v", total)
				}
				// +Inf сравнивать дальше не нужно
				return
			}
			if math.Abs(total-tt.expected) > 1e-9 {
				t.Fatalf("unexpected total: want %.2f, got %.2f", tt.expected, total)
			}
		})
	}
}
```

### Что делает тест

| № | Сценарий | Ожидаемый результат |
|---|----------|----------------------|
| 1 | `nil`‑срез `Items` | `0` (как у пустого среза) |
| 2 | Все позиции имеют `Quantity == 0` | `0` |
| 3 | Все позиции имеют `UnitPrice == 0` | `0` |
| 4 | Смешанные нулевые и положительные значения | корректная сумма (109.98) |
| 5 | Очень большие числа (`int64` × `float64`) | `+Inf` без паники |
| 6 | Отрицательные `Quantity` и `UnitPrice` (невалидные, но метод их суммирует) | `-150` |

### Почему это не дублирует существующие тесты

* В проекте уже есть `TestUnitOrderCalculateTotal*`, покрывающие обычные случаи: пустой заказ, один элемент, большой набор.  
* Здесь мы проверяем **граничные** условия, которые в тех тестах не рассматриваются (nil‑срез, нулевые/отрицательные параметры, переполнение).  
* Тест использует таблицу и `t.Run`, как и остальные unit‑тесты, но фокусируется на иных ветках кода.

Запустите:

```bash
go test ./... -run TestUnitOrderCalculateTotalEdgeCases
```

и убедитесь, что все новые кейсы проходят. Если в дальнейшем появятся новые ограничения (например, валидация отрицательных значений), тест будет сигнализировать о регрессии.

