package handler_test

import (
	"bytes"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"strconv"
	"testing"

	"beanbrew/internal/handler"
	"beanbrew/internal/repository/sqlite"
	"beanbrew/internal/usecase"
)

// ---------------------------------------------------------------------
// Вспомогательные типы, которые нужны только для этого теста
// ---------------------------------------------------------------------

// CategoryCreateReq – тело запроса на создание категории.
type CategoryCreateReq struct {
	Name        string `json:"name"`
	Description string `json:"description"`
	SortOrder   int    `json:"sort_order"`
}

// ProductCreateReq – тело запроса на создание товара.
type ProductCreateReq struct {
	Name        string  `json:"name"`
	Description string  `json:"description"`
	Price       float64 `json:"price"`
	CategoryID  int64   `json:"category_id"`
	ImageURL    string  `json:"image_url"`
	Active      bool    `json:"active"`
}

// OrderCreateReq – тело запроса на создание заказа.
type OrderCreateReq struct {
	Items []OrderItemReq `json:"items"`
}

// OrderItemReq – один элемент заказа.
type OrderItemReq struct {
	ProductID int64 `json:"product_id"`
	Quantity  int   `json:"quantity"`
}

// OrderResp – часть ответа, которую мы проверяем.
type OrderResp struct {
	ID        int64   `json:"id"`
	Status    string  `json:"status"`
	Total     float64 `json:"total"`
	CreatedAt string  `json:"created_at"`
}

// ---------------------------------------------------------------------
// Тест полного flow: категория → товар → заказ → отмена
// ---------------------------------------------------------------------

func TestAPI_FullFlow_CreateCategoryAddProductCreateOrderCancel(t *testing.T) {
	// 1️⃣ Подготовка тестовой инфраструктуры (in‑memory SQLite + HTTP‑сервер)
	db := sqlite.SetupTestDB(t) // создаёт DB, применяет миграции и seed‑данные
	defer db.Close()

	// Создаём use‑case‑слой
	catUC := usecase.NewCategoryUsecase(db.CategoryRepository())
	prodUC := usecase.NewProductUsecase(db.ProductRepository())
	orderUC := usecase.NewOrderUsecase(db.OrderRepository(), db.ProductRepository())

	// Создаём HTTP‑хендлеры и роутер
	h := handler.NewHandler(catUC, prodUC, nil, orderUC) // news‑usecase не нужен в этом тесте
	router := chi.NewRouter()
	h.RegisterRoutes(router)

	ts := httptest.NewServer(router)
	defer ts.Close()

	// -----------------------------------------------------------------
	// 2️⃣ Создаём категорию
	// -----------------------------------------------------------------
	catReq := CategoryCreateReq{
		Name:        "Espresso",
		Description: "Кофе в зернах для эспрессо‑машин",
		SortOrder:   1,
	}
	catID := postJSON(t, ts.URL+"/api/v1/categories", catReq)
	if catID == 0 {
		t.Fatalf("не удалось создать категорию")
	}

	// -----------------------------------------------------------------
	// 3️⃣ Добавляем товар в только‑что‑созданную категорию
	// -----------------------------------------------------------------
	prodReq := ProductCreateReq{
		Name:        "Arabica 500g",
		Description: "Молотый кофе арабика, 500 г",
		Price:       320.0,
		CategoryID:  catID,
		ImageURL:    "https://example.com/arabica.jpg",
		Active:      true,
	}
	prodID := postJSON(t, ts.URL+"/api/v1/products", prodReq)
	if prodID == 0 {
		t.Fatalf("не удалось создать товар")
	}

	// -----------------------------------------------------------------
	// 4️⃣ Оформляем заказ (один товар, количество 2 → ожидаем total = 640)
	// -----------------------------------------------------------------
	orderReq := OrderCreateReq{
		Items: []OrderItemReq{
			{ProductID: prodID, Quantity: 2},
		},
	}
	orderID := postJSON(t, ts.URL+"/api/v1/orders", orderReq)
	if orderID == 0 {
		t.Fatalf("не удалось создать заказ")
	}

	// Проверяем, что total посчитан правильно
	order := getOrder(t, ts.URL+"/api/v1/orders/"+strconv.FormatInt(orderID, 10))
	if order.Total != 640.0 {
		t.Fatalf("неправильный total: want 640.0, got %v", order.Total)
	}
	if order.Status != "new" {
		t.Fatalf("неправильный статус сразу после создания: want 'new', got %q", order.Status)
	}

	// -----------------------------------------------------------------
	// 5️⃣ Отменяем заказ
	// -----------------------------------------------------------------
	req, err := http.NewRequest(http.MethodPost,
		fmt.Sprintf("%s/api/v1/orders/%d/cancel", ts.URL, orderID), nil)
	if err != nil {
		t.Fatalf("создание запроса отмены: %v", err)
	}
	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		t.Fatalf("выполнение запроса отмены: %v", err)
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("ожидали 200 OK от cancel, получили %d", resp.StatusCode)
	}

	// -----------------------------------------------------------------
	// 6️⃣ Снова читаем заказ – статус должен быть «cancelled»
	// -----------------------------------------------------------------
	afterCancel := getOrder(t, ts.URL+"/api/v1/orders/"+strconv.FormatInt(orderID, 10))
	if afterCancel.Status != "cancelled" {
		t.Fatalf("статус после отмены неверный: want 'cancelled', got %q", afterCancel.Status)
	}
}

// ---------------------------------------------------------------------
// Вспомогательные функции
// ---------------------------------------------------------------------

// postJSON отправляет POST‑запрос с JSON‑телом и возвращает поле `id`
// из ответа (все API‑эндпоинты создают сущность и возвращают `{ "id": <int> }`).
func postJSON[T any](t *testing.T, url string, payload any) int64 {
	t.Helper()
	body, err := json.Marshal(payload)
	if err != nil {
		t.Fatalf("marshal payload: %v", err)
	}
	resp, err := http.Post(url, "application/json", bytes.NewReader(body))
	if err != nil {
		t.Fatalf("POST %s: %v", url, err)
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusCreated {
		t.Fatalf("POST %s: ожидаем 201 Created, получили %d", url, resp.StatusCode)
	}
	var out struct {
		ID int64 `json:"id"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&out); err != nil {
		t.Fatalf("decode response from %s: %v", url, err)
	}
	return out.ID
}

// getOrder делает GET‑запрос к /api/v1/orders/{id} и возвращает структуру OrderResp.
func getOrder(t *testing.T, url string) OrderResp {
	t.Helper()
	resp, err := http.Get(url)
	if err != nil {
		t.Fatalf("GET %s: %v", url, err)
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("GET %s: ожидаем 200 OK, получили %d", url, resp.StatusCode)
	}
	var order OrderResp
	if err := json.NewDecoder(resp.Body).Decode(&order); err != nil {
		t.Fatalf("decode order response: %v", err)
	}
	return order
}
